package com.izonehub.stores.user;import com.izonehub.stores.auth.PasswordPolicy;import org.junit.jupiter.api.Test;import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;import static org.assertj.core.api.Assertions.*;import static org.mockito.Mockito.*;class UserCommandServiceTest{@Test void refusesCreatingSystemAdministrator(){UserRepository repo=mock(UserRepository.class);UserCommandService svc=new UserCommandService(repo,new BCryptPasswordEncoder(),new PasswordPolicy());assertThatThrownBy(()->svc.createUser("Admin","a@example.com","Password1!",java.util.Set.of(Role.SYSTEM_ADMINISTRATOR),null,null)).isInstanceOf(IllegalArgumentException.class);verify(repo,never()).save(any());}}
